[CmdletBinding()]
param([Parameter(Mandatory)][string]$ProjectRoot,[switch]$Refresh)

$ErrorActionPreference='Stop';$project=(Resolve-Path -LiteralPath $ProjectRoot).Path;$studio=Join-Path $project '.studio';$root=(Resolve-Path (Join-Path $PSScriptRoot '../..')).Path;$snapshot=Join-Path $studio 'PROJECT_SNAPSHOT.md';if(-not(Test-Path $snapshot)){Copy-Item -LiteralPath (Join-Path $root 'templates/studio/PROJECT_SNAPSHOT.template.md') -Destination $snapshot;Write-Host 'Initialized .studio/PROJECT_SNAPSHOT.md';exit}
if(-not $Refresh){Write-Host 'Project snapshot preserved; use -Refresh after reviewing current state.';exit};$state=Get-Content -Raw -LiteralPath (Join-Path $studio 'PROJECT_STATE.md') -ErrorAction SilentlyContinue;$current=[regex]::Match($state,'(?im)^-\s*Current state:\s*`?([^`\r\n]+)');$snapshotText=Get-Content -Raw -LiteralPath $snapshot;$existing=[regex]::Match($snapshotText,'(?im)^Project state:\s*([^\r\n]*)');if($current.Success -and $existing.Success -and $existing.Groups[1].Value.Trim() -and $existing.Groups[1].Value.Trim() -ne $current.Groups[1].Value.Trim()){throw 'Snapshot state conflicts with PROJECT_STATE.md; preserve user edits and resolve the contradiction explicitly.'};$snapshotText=[regex]::Replace($snapshotText,'(?im)^Updated:.*$',('Updated: '+[DateTime]::UtcNow.ToString('o')));if($current.Success){$snapshotText=[regex]::Replace($snapshotText,'(?im)^Project state:.*$',('Project state: '+$current.Groups[1].Value.Trim()))};Set-Content -LiteralPath $snapshot -Value $snapshotText -Encoding utf8;Write-Host 'Project snapshot refreshed without replacing user-authored fields.'
